 19→        override fun onCreate(surfaceHolder: SurfaceHolder) {
 20→            super.onCreate(surfaceHolder)
 21→
 22→            videoFilePath = try {
 23→                this@VideoLiveWallpaperService.openFileInput("video_live_wallpaper_file_path")
 24→                    .bufferedReader().use { it.readText() }
 25→            } catch (e: Exception) {
 26→                null
 27→            }
 28→
 29→            val intentFilter = IntentFilter(VIDEO_PARAMS_CONTROL_ACTION)
 30→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
 31→                ContextCompat.registerReceiver(
