 2→import android.content.ContentUris
 3→import android.content.Context
 4→import android.database.Cursor
 5→import android.net.Uri
 6→import android.os.Build
 7→import android.os.Environment
 8→import android.provider.DocumentsContract
 9→import android.provider.MediaStore
10→
11→object DocumentUtils {
12→    /**
13→     * 获取 Uri 对应的文件路径
14→     * 注意：在 Android 10+ 上，建议直接使用 Uri 而不是文件路径
15→     */
16→    fun getPath(context: Context, uri: Uri): String? {
17→        // 对于 Android 10+，优先返回 Uri 字符串
18→        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
19→            return uri.toString()
20→        }
21→
22→        if (DocumentsContract.isDocumentUri(context, uri)) {
23→            when {
24→                isExternalStorageDocument(uri) -> {
25→                    val docId = DocumentsContract.getDocumentId(uri)
26→                    val split = docId.split(":")
27→                    val type = split[0]
28→                    if ("primary".equals(type, ignoreCase = true)) {
29→                        return "${Environment.getExternalStorageDirectory()}/${split[1]}"
30→                    }
31→                }
32→                isDownloadsDocument(uri) -> {
33→                    val id = DocumentsContract.getDocumentId(uri)
34→                    val contentUri = ContentUris.withAppendedId(
35→                        Uri.parse("content://downloads/public_downloads"),
36→                        id.toLongOrNull() ?: return null
37→                    )
38→                    return getDataColumn(context, contentUri, null, null)
39→                }
40→                isMediaDocument(uri) -> {
41→                    val docId = DocumentsContract.getDocumentId(uri)
42→                    val split = docId.split(":")
43→                    val type = split[0]
44→                    val contentUri = when (type) {
45→                        "image" -> MediaStore.Images.Media.EXTERNAL_CONTENT_URI
46→                        "video" -> MediaStore.Video.Media.EXTERNAL_CONTENT_URI
47→                        "audio" -> MediaStore.Audio.Media.EXTERNAL_CONTENT_URI
48→                        else -> null
49→                    }
50→                    val selection = "_id=?"
51→                    val selectionArgs = arrayOf(split[1])
52→                    return getDataColumn(context, contentUri, selection, selectionArgs)
53→                }
54→            }
55→        } else if ("content".equals(uri.scheme, ignoreCase = true)) {
56→            return getDataColumn(context, uri, null, null)
57→        } else if ("file".equals(uri.scheme, ignoreCase = true)) {
58→            return uri.path
59→        }
60→        return null
61→    }
62→
63→    private fun getDataColumn(
64→        context: Context,
65→        uri: Uri?,
66→        selection: String?,
67→        selectionArgs: Array<String>?
68→    ): String? {
69→        uri ?: return null
70→        context.contentResolver.query(uri, arrayOf("_data"), selection, selectionArgs, null)?.use { cursor ->
71→            if (cursor.moveToFirst()) {
72→                val columnIndex = cursor.getColumnIndexOrThrow("_data")
73→                return cursor.getString(columnIndex)
74→            }
75→        }
76→        return null
77→    }
78→
79→    private fun isExternalStorageDocument(uri: Uri) =
80→        "com.android.externalstorage.documents" == uri.authority
81→
82→    private fun isDownloadsDocument(uri: Uri) =
83→        "com.android.providers.downloads.documents" == uri.authority
84→
85→    private fun isMediaDocument(uri: Uri) =
86→        "com.android.providers.media.documents" == uri.authority
87→}
