    var desc = new ActionDescriptor();
    desc.putInteger(charIDToTypeID("Fzns"), 45);

    var minDesc = new ActionDescriptor();
    minDesc.putDouble(charIDToTypeID("Rd  "), 245.0);
    minDesc.putDouble(charIDToTypeID("Grn "), 245.0);
    minDesc.putDouble(charIDToTypeID("Bl  "), 245.0);
    desc.putObject(charIDToTypeID("Mnm "), charIDToTypeID("RGBC"), minDesc);

    executeAction(idClrR, desc, DialogModes.NO);
}

function deleteSelectedBackground(doc) {
    try {
        doc.selection.expand(1);
    } catch (e) {}
    try {
        doc.selection.feather(0.4);
    } catch (e) {}
    doc.selection.clear();
    doc.selection.deselect();
}

function addOuterGlowSafe() {
    try {
        var idsetd = charIDToTypeID("setd");
        var desc = new ActionDescriptor();
        var ref = new ActionReference();
        ref.putProperty(charIDToTypeID("Prpr"), stringIDToTypeID("layerEffects"));
        ref.putEnumerated(charIDToTypeID("Lyr "), charIDToTypeID("Ordn"), charIDToTypeID("Trgt"));
        desc.putReference(charIDToTypeID("null"), ref);

        var fxDesc = new ActionDescriptor();
        var glowDesc = new ActionDescriptor();
        glowDesc.putBoolean(charIDToTypeID("enab"), true);
        glowDesc.putEnumerated(charIDToTypeID("Md  "), charIDToTypeID("BlnM"), charIDToTypeID("Scrn"));
        glowDesc.putUnitDouble(charIDToTypeID("Opct"), charIDToTypeID("#Prc"), 35.0);

        var colorDesc = new ActionDescriptor();
        colorDesc.putDouble(charIDToTypeID("Rd  "), 255.0);
        colorDesc.putDouble(charIDToTypeID("Grn "), 255.0);
        colorDesc.putDouble(charIDToTypeID("Bl  "), 255.0);
        glowDesc.putObject(charIDToTypeID("Clr "), charIDToTypeID("RGBC"), colorDesc);

        glowDesc.putUnitDouble(charIDToTypeID("Ckmt"), charIDToTypeID("#Pxl"), 0.0);
        glowDesc.putUnitDouble(charIDToTypeID("blur"), charIDToTypeID("#Pxl"), 18.0);
        glowDesc.putBoolean(charIDToTypeID("AntA"), false);
        glowDesc.putEnumerated(charIDToTypeID("glwT"), charIDToTypeID("BETE"), charIDToTypeID("SfBL"));
        glowDesc.putUnitDouble(charIDToTypeID("Inpr"), charIDToTypeID("#Prc"), 50.0);

        fxDesc.putObject(stringIDToTypeID("outerGlow"), stringIDToTypeID("outerGlow"), glowDesc);
        desc.putObject(charIDToTypeID("T   "), stringIDToTypeID("layerEffects"), fxDesc);
        executeAction(idsetd, desc, DialogModes.NO);
    } catch (e) {}
}

function exportTransparentPng(doc) {
    if (!doc.saved || !doc.path) {
        throw new Error("请先把图片保存到磁盘，再运行脚本导出 PNG。");
    }

    var file = File(doc.path + "/" + doc.name.replace(/\.[^\.]+$/, "") + "_transparent.png");
    var options = new ExportOptionsSaveForWeb();
    options.format = SaveDocumentType.PNG;
    options.PNG8 = false;
    options.transparency = true;
    options.interlaced = false;
    options.quality = 100;
    doc.exportDocument(file, ExportType.SAVEFORWEB, options);
    return file;
}

try {
    var doc = ensureDocument();
    unlockBackgroundLayer(doc);
    duplicateActiveLayer(doc);
    selectWhiteBackground();
    deleteSelectedBackground(doc);
    addOuterGlowSafe();
    var exported = exportTransparentPng(doc);
    alert("处理完成，已导出：\n" + exported.fsName + "\n\n这是 Photoshop 25 兼容的保守版：优先保证能跑。若边缘还需要更干净，可再手工微调。\n\n建议运行方式：文件 > 脚本 > 浏览。 ");
