#target photoshop
app.bringToFront();

displayDialogs = DialogModes.NO;

function ensureDocument() {
    if (app.documents.length === 0) {
        throw new Error("请先在 Photoshop 中打开图片，再运行脚本。");
    }
    return app.activeDocument;
}

function prepareDocument(doc) {
    if (doc.mode !== DocumentMode.RGB) {
        doc.changeMode(ChangeMode.RGB);
    }
    try {
        if (doc.bitsPerChannel !== BitsPerChannelType.EIGHT) {
            doc.bitsPerChannel = BitsPerChannelType.EIGHT;
        }
    } catch (e) {}
}

function unlockAndRasterize(doc) {
    try {
        if (doc.activeLayer.isBackgroundLayer) {
            doc.activeLayer.isBackgroundLayer = false;
        }
    } catch (e) {}

    try {
        doc.activeLayer.rasterize(RasterizeType.ENTIRELAYER);
    } catch (e) {}

    try {
        doc.activeLayer.transparentPixelsLocked = false;
    } catch (e) {}
}

function duplicateActiveLayer(doc) {
    var layer = doc.activeLayer.duplicate();
    layer.name = "Auto Cutout";
    doc.activeLayer = layer;
    return layer;
}

function selectWhiteBackgroundSafe() {
    var idClrR = charIDToTypeID("ClrR");
    var desc = new ActionDescriptor();
    desc.putInteger(charIDToTypeID("Fzns"), 35);

    var minDesc = new ActionDescriptor();
    minDesc.putDouble(charIDToTypeID("Rd  "), 245.0);
    minDesc.putDouble(charIDToTypeID("Grn "), 245.0);
    minDesc.putDouble(charIDToTypeID("Bl  "), 245.0);
    desc.putObject(charIDToTypeID("Mnm "), charIDToTypeID("RGBC"), minDesc);

    executeAction(idClrR, desc, DialogModes.NO);
}

function deleteSelectedBackground(doc) {
    try { doc.selection.expand(1); } catch (e) {}
    try { doc.selection.feather(0.3); } catch (e) {}
    doc.selection.clear();
    doc.selection.deselect();
}

function exportTransparentPng(doc) {
    if (!doc.saved || !doc.path) {
        throw new Error("请先把图片保存到磁盘，再运行脚本导出 PNG。");
    }

    var file = File(doc.path + "/" + doc.name.replace(/\.[^\.]+$/, "") + "_transparent.png");
    var pngOptions = new PNGSaveOptions();
    pngOptions.compression = 0;
    pngOptions.interlaced = false;
    doc.saveAs(file, pngOptions, true, Extension.LOWERCASE);
    return file;
}

try {
    var doc = ensureDocument();
    prepareDocument(doc);
    unlockAndRasterize(doc);
    duplicateActiveLayer(doc);
    unlockAndRasterize(doc);
    selectWhiteBackgroundSafe();
    deleteSelectedBackground(doc);
    var exported = exportTransparentPng(doc);
    alert("处理完成，已导出：\n" + exported.fsName + "\n\n这是更保守的 PS 25.7 兼容版：仅执行白底删除与透明 PNG 导出。\n如果需要白色光辉，建议导出后手工加图层样式。\n\n请用：文件 > 脚本 > 浏览 运行。 ");
} catch (e) {
    alert("脚本执行失败：\n" + e.message + "\n\n如果还报错，把新截图发我，我继续修。");
}

