input.content:
#target photoshop
app.bringToFront();
displayDialogs = DialogModes.NO;

var doc = app.activeDocument;

if (doc.mode !== DocumentMode.RGB) {
    doc.changeMode(ChangeMode.RGB);
}

try {
    if (doc.bitsPerChannel !== BitsPerChannelType.EIGHT) {
        doc.bitsPerChannel = BitsPerChannelType.EIGHT;
    }
} catch (e) {}

try {
    if (doc.activeLayer.isBackgroundLayer) {
        doc.activeLayer.isBackgroundLayer = false;
    }
} catch (e) {}

var layer = doc.activeLayer.duplicate();
layer.name = "Pure Black Subject";
doc.activeLayer = layer;

try {
    doc.activeLayer.rasterize(RasterizeType.ENTIRELAYER);
} catch (e) {}

try {
    doc.activeLayer.transparentPixelsLocked = true;
} catch (e) {}

var fillColor = new SolidColor();
fillColor.rgb.red = 0;
fillColor.rgb.green = 0;
fillColor.rgb.blue = 0;
app.foregroundColor = fillColor;

doc.selection.selectAll();
doc.selection.fill(app.foregroundColor, ColorBlendMode.NORMAL, 100, false);
doc.selection.deselect();

